proof_block:
// `SingleDelivery::send_single_message(pre, post, m, dst, sm, params)` is a
// fully deterministic `open spec(checked)`:
//
//   let old_ack   = ack_state_lookup(dst, pre.send_state);
//   let new_seqno = old_ack.num_packets_acked + old_ack.un_acked.len() + 1;
//   if new_seqno > params.max_seqno {
//       &&& post == pre
//       &&& sm is None
//   } else {
//       &&& sm == Some(SingleMessage::<MT>::Message{ seqno: new_seqno, m, dst })
//       &&& post == SingleDelivery { send_state: pre.send_state.insert(dst, ...), ..pre }
//   }
//
// Both ensures-conjuncts share `(pre_self_@, m@, dst@, params)`, so the
// if/else condition `new_seqno > params.max_seqno` evaluates to the
// *same* expression in both r1- and r2-runs.  z3 returned `unknown`
// because the two `send_single_message(...)` calls were unfolded along
// disjoint `(post, sm)` chains and the case-split was never aligned
// across r1/r2.  We close the trigger gap by re-stating each alignment
// as an implication that Verus must check; every assert below is
// unconditionally provable by unfolding the open spec body on both
// sides, and uses the `#[verifier::ext_equal]` annotation on
// `SingleDelivery` / `AckState` for the post-state view equality.

let pre_v   = pre_self_@;
let post1_v = post1_self_@;
let post2_v = post2_self_@;
let params  = AbstractParameters::static_params();
let old_ack = ack_state_lookup(dst@, pre_v.send_state);
let new_seqno = old_ack.num_packets_acked + old_ack.un_acked.len() + 1;
let cond = new_seqno > params.max_seqno;

// (A) The Some/None tag of the output is determined by `cond`: any `Some`
//     witness forces the else-branch (`!cond`); any `None` witness forces
//     the then-branch (`cond`).  Since `cond` is a shared expression
//     between the two runs, mismatched Some/None tags are contradictory.
assert(forall|smv: SingleMessage<Message>, post: SingleDelivery<Message>|
    #[trigger] SingleDelivery::send_single_message(pre_v, post, m@, dst@, Some(smv), params)
        ==> !cond
            && smv == SingleMessage::<Message>::Message{ seqno: new_seqno, m: m@, dst: dst@ }
            && post == SingleDelivery::<Message> {
                    send_state: pre_v.send_state.insert(dst@,
                        AckState{
                            un_acked: old_ack.un_acked.push(smv),
                            ..old_ack }),
                    ..pre_v });
assert(forall|post: SingleDelivery<Message>|
    #[trigger] SingleDelivery::send_single_message(pre_v, post, m@, dst@, None, params)
        ==> cond && post == pre_v);

// (B) Same-tag, Some/Some: both witnesses are pinned to the same
//     `SingleMessage::Message{ seqno: new_seqno, m: m@, dst: dst@ }` and
//     both post-views are pinned to the same insert-expression, so
//     `r1->Some_0@ == r2->Some_0@` and `post1_v == post2_v`.
assert(
    r1 is Some && r2 is Some
    && SingleDelivery::send_single_message(pre_v, post1_v, m@, dst@, Some(r1->Some_0@), params)
    && SingleDelivery::send_single_message(pre_v, post2_v, m@, dst@, Some(r2->Some_0@), params)
    ==> r1->Some_0@ == r2->Some_0@ && post1_v == post2_v
);

// (C) Same-tag, None/None: both runs land in the then-branch, forcing
//     `post1_v == pre_v == post2_v`.
assert(
    SingleDelivery::send_single_message(pre_v, post1_v, m@, dst@, None, params)
    && SingleDelivery::send_single_message(pre_v, post2_v, m@, dst@, None, params)
    ==> post1_v == post2_v
);

// (D) Mismatched tags are contradictory (combining (A) on both sides).
assert(
    r1 is Some && r2 is None
    && SingleDelivery::send_single_message(pre_v, post1_v, m@, dst@, Some(r1->Some_0@), params)
    && SingleDelivery::send_single_message(pre_v, post2_v, m@, dst@, None, params)
    ==> false
);
assert(
    r1 is None && r2 is Some
    && SingleDelivery::send_single_message(pre_v, post1_v, m@, dst@, None, params)
    && SingleDelivery::send_single_message(pre_v, post2_v, m@, dst@, Some(r2->Some_0@), params)
    ==> false
);

// (E) `SingleDelivery<MT>` carries `#[verifier::ext_equal]`, so view
//     equality decomposes to per-component equality on `receive_state`
//     and `send_state`, which is exactly what `CSingleDelivery::view()`
//     projects onto each concrete field's `view()`.
assert(
    post1_v == post2_v
    ==> post1_self_.receive_state@ == post2_self_.receive_state@
        && post1_self_.send_state@ == post2_self_.send_state@
);

// (F) Push the per-component view equality through `CTombstoneTable::view`
//     and `CSendState::view` to the underlying `epmap@` Map views, which
//     are what `=~=`-extensionally determine the abstract maps.
assert(
    post1_self_.receive_state@ == post2_self_.receive_state@
    ==> post1_self_.receive_state.epmap@ =~= post2_self_.receive_state.epmap@
);
assert(
    post1_self_.send_state@ == post2_self_.send_state@
    ==> post1_self_.send_state.epmap@.map_values(|v: CAckState| v@)
        =~= post2_self_.send_state.epmap@.map_values(|v: CAckState| v@)
);
